<script setup lang="ts">
import{onMounted,reactive,ref}from'vue';import{ElMessage}from'element-plus';import{api}from'../api/client';interface Info{books:number;files:number;data_dir:string;opds_url:string}interface Backup{id:string;file_path:string;file_size:number;checksum:string;created_at:string}interface Issue{code:string;book_id?:string;file_id?:string;path?:string;message:string}interface Report{status:string;started_at:string;finished_at?:string;checked_books:number;checked_files:number;trash_entries:number;issues:Issue[]}
const info=ref<Info>(),backups=ref<Backup[]>([]),report=ref<Report>(),busy=ref('');const password=reactive({current_password:'',new_password:''});async function load(){const[i,b,s]=await Promise.all([api.get<Info>('/system/info'),api.get<Backup[]>('/system/backups'),api.get<Report>('/system/scan/status')]);info.value=i.data;backups.value=b.data;report.value=s.data}async function createBackup(){busy.value='backup';try{await api.post('/system/backups');ElMessage.success('备份已创建');backups.value=(await api.get<Backup[]>('/system/backups')).data}catch{ElMessage.error('备份失败')}finally{busy.value=''}}async function scan(){busy.value='scan';try{report.value=(await api.post<Report>('/system/scan')).data;ElMessage.success(`扫描完成，发现 ${report.value.issues.length} 个问题`)}catch{ElMessage.error('扫描失败')}finally{busy.value=''}}async function manifest(){const{data}=await api.get('/system/manifest');const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});const href=URL.createObjectURL(blob);const a=document.createElement('a');a.href=href;a.download='manifest.json';a.click();URL.revokeObjectURL(href)}async function changePassword(){try{await api.post('/auth/change-password',password);ElMessage.success('密码已修改，请重新登录');location.href='/login'}catch(e:any){ElMessage.error(e.response?.data?.error||'修改失败')}}function size(n:number){return(n/1024/1024).toFixed(1)+' MB'}onMounted(load)
</script>
<template><section><h1>系统设置</h1><el-descriptions v-if="info" border :column="2"><el-descriptions-item label="书籍">{{info.books}}</el-descriptions-item><el-descriptions-item label="文件">{{info.files}}</el-descriptions-item><el-descriptions-item label="数据目录">{{info.data_dir}}</el-descriptions-item><el-descriptions-item label="OPDS">{{info.opds_url}}</el-descriptions-item></el-descriptions><div class="panels"><el-card><template #header><div class="head"><strong>备份</strong><el-button type="primary" :loading="busy==='backup'" @click="createBackup">创建备份</el-button></div></template><el-table :data="backups" empty-text="暂无备份"><el-table-column prop="created_at" label="创建时间"/><el-table-column label="大小"><template #default="s">{{size(s.row.file_size)}}</template></el-table-column><el-table-column prop="checksum" label="SHA-256" show-overflow-tooltip/></el-table></el-card><el-card><template #header><div class="head"><strong>一致性扫描</strong><div><el-button @click="manifest">导出 Manifest</el-button><el-button type="primary" :loading="busy==='scan'" @click="scan">开始扫描</el-button></div></div></template><template v-if="report"><p>状态：{{report.status}}；检查 {{report.checked_books}} 本书、{{report.checked_files}} 个文件；回收站目录 {{report.trash_entries}} 个。</p><el-table :data="report.issues" empty-text="未发现问题"><el-table-column prop="code" label="类型"/><el-table-column prop="path" label="相对路径" show-overflow-tooltip/><el-table-column prop="message" label="说明"/></el-table></template></el-card><el-card><template #header><strong>修改密码</strong></template><el-form label-position="top"><el-form-item label="当前密码"><el-input v-model="password.current_password" type="password" show-password/></el-form-item><el-form-item label="新密码"><el-input v-model="password.new_password" type="password" show-password/></el-form-item><el-button type="primary" @click="changePassword">修改密码</el-button></el-form></el-card></div></section></template>
<style scoped>.panels{display:grid;gap:1.5rem;margin-top:1.5rem}.head{display:flex;align-items:center;justify-content:space-between}.el-form{max-width:420px}</style>
